using Payments;

namespace PaymentGateway.Tests;

[TestClass]
public sealed class PaymentGatewayTests
{
    private readonly Payments.PaymentGateway _gateway;

    public PaymentGatewayTests()
    {
        _gateway = new Payments.PaymentGateway();
    }

    // --- ChargeAsync ---

    [TestMethod]
    public async Task ChargeAsync_ValidCard_ReturnsSuccessWithChargeId()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 49.99m);

        Assert.IsTrue(result.Success);
        Assert.IsNotNull(result.ChargeId);
    }

    [TestMethod]
    [DataRow(0.01)]
    [DataRow(1.00)]
    [DataRow(9999.99)]
    public async Task ChargeAsync_VariousAmounts_Succeeds(double amount)
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", (decimal)amount);

        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_ZeroAmount_ThrowsArgumentException()
    {
        await Assert.ThrowsExactlyAsync<ArgumentException>(
            async () => await _gateway.ChargeAsync("tok_valid_visa", 0m));
    }

    [TestMethod]
    public async Task ChargeAsync_NegativeAmount_ThrowsArgumentException()
    {
        await Assert.ThrowsExactlyAsync<ArgumentException>(
            async () => await _gateway.ChargeAsync("tok_valid_visa", -10m));
    }

    [TestMethod]
    public async Task ChargeAsync_NullToken_ThrowsArgumentNullException()
    {
        await Assert.ThrowsExactlyAsync<ArgumentNullException>(
            async () => await _gateway.ChargeAsync(null!, 10m));
    }

    [TestMethod]
    public async Task ChargeAsync_EmptyToken_ThrowsArgumentException()
    {
        await Assert.ThrowsExactlyAsync<ArgumentException>(
            async () => await _gateway.ChargeAsync("", 10m));
    }

    [TestMethod]
    public async Task ChargeAsync_DeclinedCard_ReturnsFailure()
    {
        var result = await _gateway.ChargeAsync("tok_declined", 50m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_ReturnsUniqueChargeIds()
    {
        var result1 = await _gateway.ChargeAsync("tok_valid_visa", 10m);
        var result2 = await _gateway.ChargeAsync("tok_valid_visa", 20m);

        Assert.AreNotEqual(result1.ChargeId, result2.ChargeId);
    }

    // --- RefundAsync ---

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsSuccessWithRefundId()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 75m);
        var refund = await _gateway.RefundAsync(charge.ChargeId);

        Assert.IsTrue(refund.Success);
        Assert.IsNotNull(refund.RefundId);
    }

    [TestMethod]
    public async Task RefundAsync_NullChargeId_ThrowsArgumentNullException()
    {
        await Assert.ThrowsExactlyAsync<ArgumentNullException>(
            async () => await _gateway.RefundAsync(null!));
    }

    [TestMethod]
    public async Task RefundAsync_EmptyChargeId_ThrowsArgumentException()
    {
        await Assert.ThrowsExactlyAsync<ArgumentException>(
            async () => await _gateway.RefundAsync(""));
    }

    [TestMethod]
    public async Task RefundAsync_NonexistentChargeId_ReturnsFailure()
    {
        var result = await _gateway.RefundAsync("ch_nonexistent");

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task RefundAsync_AlreadyRefundedCharge_ReturnsFailure()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 100m);
        await _gateway.RefundAsync(charge.ChargeId);

        var secondRefund = await _gateway.RefundAsync(charge.ChargeId);

        Assert.IsFalse(secondRefund.Success);
    }
}

